242→/// Physics for thrown box motion. Applies gravity and updates rotation
243→/// based on stored rotation velocities (wobble effect when thrown).
244→void itBox_UnkMotion1_Phys(Item_GObj* gobj)
245→{
246→    HSD_JObj* jobj = GET_JOBJ(gobj);
247→    Item* ip = GET_ITEM(gobj);
248→    ItemAttr* attr = ip->xCC_item_attr;
249→    double const tau = M_TAU;
250→
251→    it_80272860(gobj, attr->x10_fall_speed, attr->x14_fall_speed_max);
252→
253→    if (ip->xDD4_itemVar.box.spawned_gobj != NULL) {
254→        Quaternion rot;
255→        ip->x40_vel.z *= 0.95F;
256→
257→        HSD_JObjGetRotation(jobj, &rot);
258→
259→        rot.x += ip->xDD4_itemVar.box.rot_vel_x;
260→        if (rot.x > tau) {
261→            rot.x -= tau;
262→        } else if (rot.x < -tau) {
263→            rot.x += tau;
264→        }
265→
266→        rot.y += ip->xDD4_itemVar.box.rot_vel_y;
267→        if (rot.y > tau) {
268→            rot.y -= tau;
269→        } else if (rot.y < -tau) {
270→            rot.y += tau;
271→        }
272→
273→        HSD_JObjSetRotation(jobj, &rot);
274→    }
275→}
